      })

diagram.d2:
direction: right
leagueMember: { class: changed }
user: { class: store }
pick: { class: store }
golfer: { class: store }
tournamentResult: { class: store }
leagueMember -> user: inner join
leagueMember -> pick: left join (this week, LOCKED)
pick -> golfer: left join
pick -> tournamentResult: left join (earnings, finish)

diagram.mermaid:
flowchart LR
  LM[leagueMember active] -->|inner| U[user]
  LM -->|left join: this week, LOCKED| P[pick]
  P -->|left| G[golfer]
  P -->|left| TR[tournamentResult]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class LM changed;
  class U,P,G,TR store;
